+#[cfg(feature = "distributed")]
+fn build_allowlist(entries: &[String]) -> HashSet<String> {
+    entries
+        .iter()
+        .map(|entry| normalize_identity(entry))
+        .filter(|entry| !entry.is_empty())
+        .collect()
+}
